
package com.example.taxgap.repository; import com.example.taxgap.domain.entity.ExceptionRecord; import com.example.taxgap.domain.enums.Severity; import org.springframework.data.jpa.repository.*; import java.util.List; public interface ExceptionRecordRepository extends JpaRepository<ExceptionRecord, Long> { List<ExceptionRecord> findByCustomerId(String customerId); List<ExceptionRecord> findBySeverity(Severity severity); List<ExceptionRecord> findByRuleName(String ruleName); @Query("select count(e) from ExceptionRecord e") long total(); @Query("select count(e) from ExceptionRecord e where e.severity = 'HIGH'") long high(); @Query("select count(e) from ExceptionRecord e where e.severity = 'MEDIUM'") long medium(); @Query("select count(e) from ExceptionRecord e where e.severity = 'LOW'") long low(); @Query("select e.customerId, count(e) from ExceptionRecord e group by e.customerId") List<Object[]> perCustomer(); }
